test.exp:
let hostPattern = /^streams-[a-z]\.fishtank\.live$/;
let urlObj = new URL(details.url);
return hostPattern.test(urlObj.hostname);

beforeSendHeaders.exp:
let headersInit = {
	"user-agent": "Mozilla/5.0",
	"referer": "https://www.fishtank.live",
	"origin": "https://www.fishtank.live"
};
let headers = Object.entries(headersInit)
	.filter(([k, v]) => v !== null)
	.map(([k, v]) => ({ name: k, value: v }));
for (let header of details.requestHeaders) {
	let name = header.name.toLowerCase();
	if (name in headersInit) continue;
	headers.push(header);
}
return { requestHeaders: headers };
